ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?minimum_years ?preferred_years WHERE {
  ?jobs a :Jobs .
  ?jobs p:Minimum_Years ?minimum_years .
  ?jobs p:Preferred_Years ?preferred_years .
  ?jobs p:Salary ?salary_o .
}
ORDER BY DESC(?salary_o)
LIMIT 1 }
  component: { SELECT ?preferred_years WHERE {
  ?jobs a :Jobs .
  ?jobs p:Preferred_Years ?preferred_years .
  ?jobs p:Salary ?salary_o .
}
ORDER BY DESC(?salary_o)
LIMIT 1 }
  component_2: { SELECT ?minimum_years WHERE {
  ?jobs a :Jobs .
  ?jobs p:Minimum_Years ?minimum_years .
  ?jobs p:Salary ?salary_o .
}
ORDER BY DESC(?salary_o)
LIMIT 1 }
}
